class Solution {
public:
    int maxScore(vector<int>& nums) {
        int n = nums.size();
        int m = n / 2;
        vector<int> dp(1 << n, 0);
        for (int mask = 1; mask < (1 << n); ++mask) {
            int k = __builtin_popcount(mask);
            if (k % 2) continue;
            int step = k / 2;
            for (int i = 0; i < n; ++i) {
                if (!(mask & (1 << i))) continue;
                for (int j = i + 1; j < n; ++j) {
                    if (!(mask & (1 << j))) continue;
                    int prev = mask ^ (1 << i) ^ (1 << j);
                    int g = gcd(nums[i], nums[j]);
                    dp[mask] = max(dp[mask], dp[prev] + step * g);
                }
            }
        }
        return dp[(1 << n) - 1];
    }
};
